files.content:
:host {
  display: block;
  box-sizing: border-box;
  width: var(--_settings-card-width);
  max-width: 100%;
  border: none;
  border-radius: var(--dimension-radius-025);
  background-color: var(--color-background-primary);
  box-shadow: 0 0 0 var(--dimension-stroke-width-012) var(--color-border-tertiary);
}

:host(.settings-section-card--editing) {
  background-color: var(--color-background-bold-brand);
  box-shadow: 0 0 0 var(--dimension-stroke-width-025) var(--color-border-bold-brand);
}

.settings-section-card__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--dimension-space-100);
  height: var(--dimension-size-600);
  padding: var(--dimension-space-100);
  background-color: var(--color-background-secondary);
  border-bottom: var(--dimension-stroke-width-012) solid var(--color-border-tertiary);
  box-sizing: border-box;
}

:host(.settings-section-card--editing) .settings-section-card__header {
  background-color: transparent;
  border-bottom-color: transparent;
}

.settings-section-card__title-wrap {
  flex: 1 1 auto;
  min-width: 0;
  display: flex;
  align-items: center;
  padding: var(--dimension-space-075);
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
}

.settings-section-card__title {
  display: inline-flex;
  align-items: center;
  min-width: 0;
  padding: var(--dimension-space-025);
}

.settings-section-card__actions {
  display: flex;
  flex-shrink: 0;
  align-items: center;
  gap: var(--dimension-space-100);
}

.settings-section-card__body {
  min-height: var(--dimension-card-width-sm);
  border-radius: 0 0 var(--dimension-radius-025) var(--dimension-radius-025);
  background-color: var(--color-background-primary);
}

:host(.settings-section-card--editing) .settings-section-card__body {
  border-radius: var(--dimension-radius-025);
}

import { Component, Event, EventEmitter, h, Host, Prop } from '@stencil/core';

export type SettingsSectionCardWidth = 'xs' | 'sm' | 'md' | 'lg';

const CARD_WIDTH_VARS: Record<SettingsSectionCardWidth, string> = {
  xs: 'var(--dimension-card-width-xs)',
  sm: 'var(--dimension-card-width-sm)',
  md: 'var(--dimension-card-width-md)',
  lg: 'var(--dimension-card-width-lg)',
};

const FAINT_BRAND_TITLE_COLOR = 'var(--color-foreground-faint-brand)';

@Component({
  tag: 'ds-settings-section-card',
  styleUrl: 'SettingsSectionCard.css',
  scoped: true,
})
export class SettingsSectionCard {
  /** Section heading shown in the card header. */
  @Prop() heading!: string;

  /** Card width token. */
  @Prop() cardWidth: SettingsSectionCardWidth = 'md';

  /** Controlled edit state — parent owns single-edit orchestration. */
  @Prop() editing = false;

  /** Emits when the user enters or exits edit mode. */
  @Event() dsEditingChange!: EventEmitter<boolean>;

  private enterEdit = () => {
    this.dsEditingChange.emit(true);
  };

  private exitEdit = () => {
    this.dsEditingChange.emit(false);
  };

  render() {
    const editing = this.editing;

    return (
      <Host
        class={{
          'settings-section-card': true,
          'settings-section-card--editing': editing,
        }}
        style={{ '--_settings-card-width': CARD_WIDTH_VARS[this.cardWidth] }}
      >
        <header class="settings-section-card__header">
          <div class="settings-section-card__title-wrap">
            <ds-text
              class="settings-section-card__title"
              variant="text-title-small"
              color={editing ? FAINT_BRAND_TITLE_COLOR : 'primary'}
              as="h2"
            >
              {this.heading}
            </ds-text>
          </div>
          {!editing ? (
            <ds-button-unfilled-icon
              type="button"
              icon="Pencil"
              aria-label="Edit"
              onDsClick={this.enterEdit}
            />
          ) : (
            <div class="settings-section-card__actions">
              <ds-button-unfilled-icon
                type="button"
                icon="Cross"
                backgroundContrast="bold"
                has-border
                aria-label="Cancel"
                onDsClick={this.exitEdit}
              />
              <ds-button-filled
                type="button"
                icon="Check"
                intent="brand"
                contrast="faint"
                aria-label="Save"
                onDsClick={this.exitEdit}
              />
            </div>
          )}
        </header>
        <div class="settings-section-card__body">
          <slot />
        </div>
      </Host>
    );
  }
}
